import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [students, setStudents] = useState([]);
  const [search, setSearch] = useState("");

  useEffect(() => {
    // Waxaan xogta ka dalbaneynaa Matoorka (Port 3000)
    axios.get('http://localhost:3000/students')
      .then(res => setStudents(res.data))
      .catch(err => console.error("Cillad Matoorka!", err));
  }, []);

  // Shaqada Raadinta (Search bar)
  const filtered = students.filter(s => 
    s.magaca.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div style={{ padding: '40px', fontFamily: 'Segoe UI, Arial', backgroundColor: '#f0f2f5', minHeight: '100vh' }}>
      <div style={{ maxWidth: '900px', margin: '0 auto' }}>
        <h1 style={{ color: '#1a73e8', textAlign: 'center', marginBottom: '30px' }}>Nidaamka Xaadiriska Dugsiga</h1>

        {/* Search Input */}
        <input 
          type="text" 
          placeholder="Raadi magaca ardayga..." 
          style={{ width: '100%', padding: '15px', borderRadius: '10px', border: '1px solid #ddd', marginBottom: '20px', fontSize: '16px' }}
          onChange={(e) => setSearch(e.target.value)}
        />

        <div style={{ backgroundColor: 'white', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 4px 15px rgba(0,0,0,0.1)' }}>
          <table width="100%" style={{ borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ backgroundColor: '#1a73e8', color: 'white', textAlign: 'left' }}>
                <th style={{ padding: '18px' }}>ID</th>
                <th style={{ padding: '18px' }}>Magaca Ardayga</th>
                <th style={{ padding: '18px' }}>Fasalka</th>
                <th style={{ padding: '18px' }}>Xaadiris</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(s => (
                <tr key={s.id} style={{ borderBottom: '1px solid #eee' }}>
                  <td style={{ padding: '15px' }}>{s.id}</td>
                  <td style={{ padding: '15px', fontWeight: 'bold' }}>{s.magaca}</td>
                  <td style={{ padding: '15px' }}>{s.fasalka}</td>
                  <td style={{ padding: '15px' }}>
                    <button style={{ backgroundColor: '#28a745', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '6px', cursor: 'pointer', marginRight: '5px' }} onClick={() => alert(`${s.magaca} waa la xadiiriyay!`)}>√ Sax</button>
                    <button style={{ backgroundColor: '#dc3545', color: 'white', border: 'none', padding: '8px 15px', borderRadius: '6px', cursor: 'pointer' }}>X Maqan</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default App;
